import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import "./Profile.css";

export default function Profile() {
  const navigate = useNavigate();

  // Load from localStorage
  const [name, setName] = useState(localStorage.getItem("userName") || "");
  const [roll] = useState(localStorage.getItem("rollNumber") || "");
  const [email, setEmail] = useState(localStorage.getItem("email") || "");
  const [phone, setPhone] = useState(localStorage.getItem("phoneNumber") || "");
  const [year, setYear] = useState(localStorage.getItem("year") || "");
  const [semester, setSemester] = useState(localStorage.getItem("semester") || "");
  const [photo, setPhoto] = useState(localStorage.getItem("profilePhoto") || "");

  function handleLogout() {
    localStorage.clear();
    navigate("/login");
  }

  function handleSave(e) {
    e.preventDefault();
    localStorage.setItem("userName", name);
    localStorage.setItem("email", email);
    localStorage.setItem("phoneNumber", phone);
    localStorage.setItem("year", year);
    localStorage.setItem("semester", semester);
    if (photo) {
      localStorage.setItem("profilePhoto", photo);
    }
    alert("Profile updated!");
  }

  function handlePhotoUpload(e) {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhoto(reader.result);
      };
      reader.readAsDataURL(file);
    }
  }

  return (
    <div className="profile-page">
      <div className="profile-card">
        <div className="profile-header">
          <img
            src={photo || "https://via.placeholder.com/120x150.png?text=Passport+Photo"}
            alt="Profile"
            className="profile-photo"
          />
          <input
            type="file"
            accept="image/*"
            onChange={handlePhotoUpload}
          />
        </div>

        <form onSubmit={handleSave} className="profile-info">
          <table>
            <tbody>
              <tr>
                <td><strong>Roll No:</strong></td>
                <td>{roll}</td>
              </tr>
              <tr>
                <td><strong>Name:</strong></td>
                <td>
                  <input
                    type="text"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                  />
                </td>
              </tr>
              <tr>
                <td><strong>Email:</strong></td>
                <td>
                  <input
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    required
                  />
                </td>
              </tr>
              <tr>
                <td><strong>Contact:</strong></td>
                <td>
                  <input
                    type="tel"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    required
                  />
                </td>
              </tr>
              <tr>
                <td><strong>Year:</strong></td>
                <td>
                  <input
                    type="text"
                    value={year}
                    onChange={(e) => setYear(e.target.value)}
                    required
                  />
                </td>
              </tr>
              <tr>
                <td><strong>Semester:</strong></td>
                <td>
                  <input
                    type="text"
                    value={semester}
                    onChange={(e) => setSemester(e.target.value)}
                    required
                  />
                </td>
              </tr>
            </tbody>
          </table>
          <div className="profile-actions">
            <button type="submit" className="save-btn">Save Changes</button>
            <Link to="/dashboard" className="back-btn">← Back</Link>
            <button type="button" className="logout-btn" onClick={handleLogout}>Logout</button>
          </div>
        </form>
      </div>
    </div>
  );
}
